import { useRef } from "react";
import {
  motion,
  useMotionValue,
  useMotionTemplate,
  useAnimationFrame,
  type MotionValue,
} from "framer-motion";

const CELL = 40;

interface GridPatternProps {
  offsetX: MotionValue<number>;
  offsetY: MotionValue<number>;
  strokeColor: string;
  strokeWidth: number;
}

const GridPattern = ({ offsetX, offsetY, strokeColor, strokeWidth }: GridPatternProps) => {
  const transform = useMotionTemplate`translate(${offsetX}px, ${offsetY}px)`;
  return (
    <svg width="100%" height="100%" className="absolute inset-0">
      <defs>
        <pattern
          id={`grid-${strokeColor.replace(/[^a-z0-9]/gi, "")}`}
          width={CELL}
          height={CELL}
          patternUnits="userSpaceOnUse"
        >
          <path
            d={`M ${CELL} 0 L 0 0 0 ${CELL}`}
            fill="none"
            stroke={strokeColor}
            strokeWidth={strokeWidth}
          />
        </pattern>
      </defs>
      <motion.rect
        x={-CELL}
        y={-CELL}
        width="calc(100% + 80px)"
        height="calc(100% + 80px)"
        fill={`url(#grid-${strokeColor.replace(/[^a-z0-9]/gi, "")})`}
        style={{ transform }}
      />
    </svg>
  );
};

interface InfiniteGridProps {
  className?: string;
}

export const InfiniteGrid = ({ className }: InfiniteGridProps) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const mouseX = useMotionValue(-9999);
  const mouseY = useMotionValue(-9999);

  const baseOffsetX = useMotionValue(0);
  const baseOffsetY = useMotionValue(0);
  const accentOffsetX = useMotionValue(0);
  const accentOffsetY = useMotionValue(0);

  useAnimationFrame(() => {
    baseOffsetX.set((baseOffsetX.get() + 0.25) % CELL);
    baseOffsetY.set((baseOffsetY.get() + 0.25) % CELL);
    accentOffsetX.set((accentOffsetX.get() + 0.5) % CELL);
    accentOffsetY.set((accentOffsetY.get() + 0.5) % CELL);
  });

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    mouseX.set(e.clientX - rect.left);
    mouseY.set(e.clientY - rect.top);
  };

  const handleMouseLeave = () => {
    mouseX.set(-9999);
    mouseY.set(-9999);
  };

  const accentMask = useMotionTemplate`radial-gradient(280px circle at ${mouseX}px ${mouseY}px, black, transparent 70%)`;

  return (
    <div
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      aria-hidden
      className={
        "absolute inset-0 overflow-hidden pointer-events-auto " + (className ?? "")
      }
    >
      {/* Soft background wash */}
      <div className="absolute inset-0 bg-gradient-to-b from-background via-background to-background" />

      {/* Base subtle grid */}
      <div className="absolute inset-0 opacity-60">
        <GridPattern
          offsetX={baseOffsetX}
          offsetY={baseOffsetY}
          strokeColor="hsl(var(--border))"
          strokeWidth={1}
        />
      </div>

      {/* Accent grid revealed by cursor */}
      <motion.div
        className="absolute inset-0"
        style={{
          WebkitMaskImage: accentMask,
          maskImage: accentMask,
        }}
      >
        <GridPattern
          offsetX={accentOffsetX}
          offsetY={accentOffsetY}
          strokeColor="hsl(var(--accent))"
          strokeWidth={1.25}
        />
      </motion.div>

      {/* Top + bottom fade for legibility */}
      <div className="absolute inset-x-0 top-0 h-24 bg-gradient-to-b from-background to-transparent pointer-events-none" />
      <div className="absolute inset-x-0 bottom-0 h-32 bg-gradient-to-t from-background to-transparent pointer-events-none" />
    </div>
  );
};

export default InfiniteGrid;

from __future__ import annotations

import asyncio
import logging
import shutil
import time
from contextlib import asynccontextmanager
from pathlib import Path
from uuid import UUID

from fastapi import FastAPI, File, Form, HTTPException, Request, UploadFile
from fastapi.middleware.cors import CORSMiddleware
from fastapi.responses import FileResponse, JSONResponse

from app.config import get_settings
from app.integrations.tavily import TavilyClient
from app.jobs import JobStore
from app.pipeline import run_pipeline
from app.schemas import GenerateResponse, JobStatus, JobStep

logger = logging.getLogger(__name__)

settings = get_settings()
job_store = JobStore()
REQUEST_TIMEOUT_SECONDS = 240
STALE_TMP_AGE_SECONDS = 30 * 60
MAX_UPLOAD_BYTES = 25 * 1024 * 1024
TMP_ROOT = Path("/tmp")


@asynccontextmanager
async def lifespan(_: FastAPI):
    cleanup_stale_tmp_jobs()
    yield
    cleanup_stale_tmp_jobs()


app = FastAPI(title="CorpuScan API", lifespan=lifespan)

_origins = settings.cors_origins_list
# CORS spec: credentials cannot be combined with wildcard origins.
_allow_credentials = "*" not in _origins
logger.info("CORS origins: %s (credentials=%s)", _origins, _allow_credentials)

app.add_middleware(
    CORSMiddleware,
    allow_origins=_origins,
    allow_credentials=_allow_credentials,
    allow_methods=["*"],
    allow_headers=["*"],
)


@app.middleware("http")
async def request_timeout_middleware(request: Request, call_next):
    is_poll = request.method == "GET" and request.url.path.startswith("/jobs/") and not request.url.path.endswith(
        "/video"
    )
    if not is_poll:
        logger.info(
            "%s %s from %s",
            request.method,
            request.url.path,
            request.headers.get("origin", "unknown"),
        )
    try:
        response = await asyncio.wait_for(call_next(request), timeout=REQUEST_TIMEOUT_SECONDS)
    except TimeoutError:
        logger.error("Request timed out: %s %s", request.method, request.url.path)
        return JSONResponse(status_code=504, content={"detail": "Request timed out."})
    if not is_poll:
        logger.info("%s %s → %s", request.method, request.url.path, response.status_code)
    return response


@app.get("/health")
async def health() -> dict[str, bool]:
    return {"ok": True}


@app.post("/generate", response_model=GenerateResponse)
async def generate(
    file: UploadFile | None = File(default=None),
    url: str | None = Form(default=None),
    query: str | None = Form(default=None),
) -> GenerateResponse:
    provided_count = sum(1 for value in [file, url, query] if value)
    if provided_count != 1:
        raise HTTPException(status_code=400, detail="Provide exactly one input: file, url, or query.")

    source_text = await _resolve_source_text(file=file, url=url, query=query)
    if not source_text.strip():
        raise HTTPException(status_code=400, detail="Could not extract text from the provided source.")

    job_id = job_store.create()
    job_store.update_step(job_id, step=JobStep.INGEST, progress=10)
    asyncio.create_task(run_pipeline(job_store, job_id, source_text))
    return GenerateResponse(job_id=job_id)


@app.get("/jobs/{job_id}", response_model=JobStatus)
async def get_job(job_id: str) -> JobStatus:
    safe_id = _validate_job_id(job_id)
    job = job_store.get(safe_id)
    if job is None:
        raise HTTPException(status_code=404, detail="Job not found.")
    return job.to_status()


@app.get("/jobs/{job_id}/video")
async def get_job_video(job_id: str, download: int = 0) -> FileResponse:
    safe_id = _validate_job_id(job_id)
    video_path = TMP_ROOT / safe_id / "final.mp4"
    if not video_path.exists():
        raise HTTPException(status_code=404, detail="Video not found.")
    headers: dict[str, str] = {}
    if download == 1:
        headers["Content-Disposition"] = f'attachment; filename="{safe_id}.mp4"'
    return FileResponse(video_path, media_type="video/mp4", headers=headers)


def _validate_job_id(job_id: str) -> str:
    # Job IDs are UUID4 strings (see JobStore.create). Reject anything else
    # to prevent path traversal into /tmp/..
    try:
        return str(UUID(job_id))
    except (ValueError, AttributeError) as exc:
        raise HTTPException(status_code=404, detail="Job not found.") from exc


async def _resolve_source_text(
    *, file: UploadFile | None, url: str | None, query: str | None
) -> str:
    if file is not None:
        from app.ingest import extract_pdf_text

        file_bytes = await file.read()
        if len(file_bytes) > MAX_UPLOAD_BYTES:
            raise HTTPException(
                status_code=413,
                detail=f"File too large. Max {MAX_UPLOAD_BYTES // (1024 * 1024)} MB.",
            )
        return extract_pdf_text(file_bytes)

    tavily_client = TavilyClient(api_key=settings.tavily_api_key)
    if url:
        return await tavily_client.extract(url)
    if query:
        results = await tavily_client.search(query)
        if not results:
            raise HTTPException(status_code=404, detail="No search results found for the provided query.")
        return await tavily_client.extract(results[0].url)
    return ""


def cleanup_stale_tmp_jobs(now_ts: float | None = None) -> None:
    now = now_ts if now_ts is not None else time.time()
    if not TMP_ROOT.exists():
        return
    for child in TMP_ROOT.iterdir():
        if not child.is_dir():
            continue
        try:
            UUID(child.name)
        except ValueError:
            continue
        try:
            age_seconds = now - child.stat().st_mtime
            if age_seconds > STALE_TMP_AGE_SECONDS:
                shutil.rmtree(child, ignore_errors=True)
        except OSError:
            continue

export type JobStatus = "pending" | "running" | "done" | "error";

export type BackendStep =
  | "ingest"
  | "finance"
  | "scripter"
  | "tts"
  | "hera_plan"
  | "hera_render"
  | "compose"
  | "done";

export interface JobState {
  status: JobStatus;
  step: BackendStep;
  progress: number;
  error?: string;
  video_url?: string;
}

export interface GenerateInput {
  file?: File;
  url?: string;
  query?: string;
}

const BASE_URL: string =
  (import.meta.env.VITE_API_BASE_URL as string | undefined) ?? "http://localhost:8000";

const DEV: boolean = Boolean(import.meta.env.DEV);

export function getApiBaseUrl(): string {
  return BASE_URL;
}

export async function postGenerate(input: GenerateInput): Promise<{ job_id: string }> {
  const form = new FormData();
  if (input.file) form.append("file", input.file);
  if (input.url) form.append("url", input.url);
  if (input.query) form.append("query", input.query);

  if (DEV) console.log("[api] POST /generate →", BASE_URL);
  const res = await fetch(`${BASE_URL}/generate`, {
    method: "POST",
    body: form,
  });

  if (!res.ok) {
    const text = await res.text().catch(() => "");
    if (DEV) console.error("[api] POST /generate failed", res.status, text);
    throw new Error(text || `Request failed (${res.status})`);
  }

  const data = (await res.json()) as { job_id: string };
  if (DEV) console.log("[api] POST /generate ok, job_id=", data.job_id);
  return data;
}

export async function getJob(jobId: string): Promise<JobState> {
  const res = await fetch(`${BASE_URL}/jobs/${encodeURIComponent(jobId)}`);
  if (!res.ok) {
    if (DEV) console.error("[api] GET /jobs/%s failed", jobId, res.status);
    throw new Error(`Failed to fetch job (${res.status})`);
  }
  return (await res.json()) as JobState;
}

export function getVideoUrl(jobId: string): string {
  return `${BASE_URL}/jobs/${encodeURIComponent(jobId)}/video`;
}

