import { Check } from "lucide-react";
import type { BackendStep } from "@/lib/api";

interface JobProgressProps {
  step: BackendStep | null;
  progress: number;
}

interface UiStep {
  key: string;
  label: string;
  backendSteps: BackendStep[];
}

const UI_STEPS: UiStep[] = [
  { key: "ingest", label: "Reading source material", backendSteps: ["ingest"] },
  { key: "finance", label: "Extracting key facts", backendSteps: ["finance"] },
  { key: "scripter", label: "Writing voiceover script", backendSteps: ["scripter"] },
  { key: "tts", label: "Recording narration", backendSteps: ["tts"] },
  { key: "hera", label: "Generating motion graphics", backendSteps: ["hera_plan", "hera_render"] },
  { key: "compose", label: "Rendering final video", backendSteps: ["compose"] },
];

const ORDER: BackendStep[] = ["ingest", "finance", "scripter", "tts", "hera_plan", "hera_render", "compose", "done"];

function stepState(uiStep: UiStep, current: BackendStep | null): "pending" | "running" | "done" {
  if (!current) return "pending";
  const currentIdx = ORDER.indexOf(current);
  const stepMaxIdx = Math.max(...uiStep.backendSteps.map((s) => ORDER.indexOf(s)));
  if (current === "done") return "done";
  if (uiStep.backendSteps.includes(current)) return "running";
  if (currentIdx > stepMaxIdx) return "done";
  return "pending";
}

export const JobProgress = ({ step, progress }: JobProgressProps) => {
  return (
    <div>
      <ul className="space-y-3">
        {UI_STEPS.map((s) => {
          const state = stepState(s, step);
          return (
            <li key={s.key} className="flex items-center gap-3">
              <span className="inline-flex h-6 w-6 items-center justify-center shrink-0">
                {state === "done" && (
                  <span className="h-6 w-6 rounded-full bg-accent text-accent-foreground inline-flex items-center justify-center">
                    <Check className="h-3.5 w-3.5" aria-hidden />
                  </span>
                )}
                {state === "running" && (
                  <span className="relative inline-flex h-6 w-6 items-center justify-center">
                    <span className="absolute inline-flex h-3 w-3 rounded-full bg-accent/40 animate-ping" />
                    <span className="relative inline-flex h-3 w-3 rounded-full bg-accent" />
                  </span>
                )}
                {state === "pending" && (
                  <span className="h-3 w-3 rounded-full bg-gray-200" />
                )}
              </span>
              <span
                className={`text-sm ${
                  state === "pending"
                    ? "text-secondary"
                    : state === "running"
                      ? "text-primary font-medium"
                      : "text-primary"
                }`}
              >
                {s.label}
              </span>
            </li>
          );
        })}
      </ul>

      <div className="mt-8">
        <div className="flex items-center justify-between mb-2">
          <span className="text-xs text-secondary uppercase tracking-wider font-semibold">
            Progress
          </span>
          <span className="font-mono text-xs text-secondary">{Math.round(progress)}%</span>
        </div>
        <div className="w-full bg-gray-200 rounded-full h-2 overflow-hidden">
          <div
            className="h-2 bg-accent rounded-full transition-all duration-500 ease-out"
            style={{ width: `${Math.max(0, Math.min(100, progress))}%` }}
          />
        </div>
      </div>
    </div>
  );
};

export default JobProgress;

import { useEffect, useRef, useState } from "react";
import { getJob, getVideoUrl, type BackendStep, type JobStatus } from "@/lib/api";

interface UseJobStatusResult {
  status: JobStatus | null;
  step: BackendStep | null;
  progress: number;
  error: string | null;
  videoUrl: string | null;
}

const POLL_MS = 1500;

export function useJobStatus(jobId: string | undefined): UseJobStatusResult {
  const [status, setStatus] = useState<JobStatus | null>(null);
  const [step, setStep] = useState<BackendStep | null>(null);
  const [progress, setProgress] = useState<number>(0);
  const [error, setError] = useState<string | null>(null);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const cancelled = useRef<boolean>(false);

  useEffect(() => {
    if (!jobId) return;
    cancelled.current = false;
    let timer: number | undefined;

    const tick = async (): Promise<void> => {
      try {
        const job = await getJob(jobId);
        if (cancelled.current) return;
        setStatus(job.status);
        setStep(job.step);
        setProgress(Math.max(0, Math.min(100, job.progress)));
        if (job.error) setError(job.error);
        if (job.status === "done") {
          setVideoUrl(job.video_url ?? getVideoUrl(jobId));
          return;
        }
        if (job.status === "error") return;
        timer = window.setTimeout(tick, POLL_MS);
      } catch (err) {
        if (cancelled.current) return;
        setError(err instanceof Error ? err.message : "Failed to fetch job");
        timer = window.setTimeout(tick, POLL_MS);
      }
    };

    void tick();

    return () => {
      cancelled.current = true;
      if (timer !== undefined) window.clearTimeout(timer);
    };
  }, [jobId]);

  return { status, step, progress, error, videoUrl };
}

export type JobStatus = "pending" | "running" | "done" | "error";

export type BackendStep =
  | "ingest"
  | "finance"
  | "scripter"
  | "tts"
  | "hera_plan"
  | "hera_render"
  | "compose"
  | "done";

export interface JobState {
  status: JobStatus;
  step: BackendStep;
  progress: number;
  error?: string;
  video_url?: string;
}

export interface GenerateInput {
  file?: File;
  url?: string;
  query?: string;
}

const BASE_URL: string =
  (import.meta.env.VITE_API_BASE_URL as string | undefined) ?? "http://localhost:8000";

const DEV: boolean = Boolean(import.meta.env.DEV);

export function getApiBaseUrl(): string {
  return BASE_URL;
}

export async function postGenerate(input: GenerateInput): Promise<{ job_id: string }> {
  const form = new FormData();
  if (input.file) form.append("file", input.file);
  if (input.url) form.append("url", input.url);
  if (input.query) form.append("query", input.query);

  if (DEV) console.log("[api] POST /generate →", BASE_URL);
  const res = await fetch(`${BASE_URL}/generate`, {
    method: "POST",
    body: form,
  });

  if (!res.ok) {
    const text = await res.text().catch(() => "");
    if (DEV) console.error("[api] POST /generate failed", res.status, text);
    throw new Error(text || `Request failed (${res.status})`);
  }

  const data = (await res.json()) as { job_id: string };
  if (DEV) console.log("[api] POST /generate ok, job_id=", data.job_id);
  return data;
}

export async function getJob(jobId: string): Promise<JobState> {
  const res = await fetch(`${BASE_URL}/jobs/${encodeURIComponent(jobId)}`);
  if (!res.ok) {
    if (DEV) console.error("[api] GET /jobs/%s failed", jobId, res.status);
    throw new Error(`Failed to fetch job (${res.status})`);
  }
  return (await res.json()) as JobState;
}

export function getVideoUrl(jobId: string): string {
  return `${BASE_URL}/jobs/${encodeURIComponent(jobId)}/video`;
}

