import { useEffect, useRef, useState } from "react";
import { getJob, getVideoUrl, type BackendStep, type JobStatus } from "@/lib/api";

interface UseJobStatusResult {
  status: JobStatus | null;
  step: BackendStep | null;
  progress: number;
  error: string | null;
  videoUrl: string | null;
  heraCompletedClips: number;
  heraTotalClips: number;
  heraAttempt: number;
  heraMaxAttempts: number;
}

const POLL_MS = 1500;

export function useJobStatus(jobId: string | undefined): UseJobStatusResult {
  const [status, setStatus] = useState<JobStatus | null>(null);
  const [step, setStep] = useState<BackendStep | null>(null);
  const [progress, setProgress] = useState<number>(0);
  const [error, setError] = useState<string | null>(null);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [heraCompletedClips, setHeraCompletedClips] = useState<number>(0);
  const [heraTotalClips, setHeraTotalClips] = useState<number>(0);
  const [heraAttempt, setHeraAttempt] = useState<number>(0);
  const [heraMaxAttempts, setHeraMaxAttempts] = useState<number>(0);
  const cancelled = useRef<boolean>(false);

  useEffect(() => {
    if (!jobId) return;
    cancelled.current = false;
    let timer: number | undefined;

    const tick = async (): Promise<void> => {
      try {
        const job = await getJob(jobId);
        if (cancelled.current) return;
        setStatus(job.status);
        setStep(job.step);
        setProgress(Math.max(0, Math.min(100, job.progress)));
        setHeraCompletedClips(Math.max(0, job.hera_completed_clips ?? 0));
        setHeraTotalClips(Math.max(0, job.hera_total_clips ?? 0));
        setHeraAttempt(Math.max(0, job.hera_attempt ?? 0));
        setHeraMaxAttempts(Math.max(0, job.hera_max_attempts ?? 0));
        if (job.error) setError(job.error);
        if (job.status === "done") {
          setVideoUrl(job.video_url ?? getVideoUrl(jobId));
          return;
        }
        if (job.status === "error") return;
        timer = window.setTimeout(tick, POLL_MS);
      } catch (err) {
        if (cancelled.current) return;
        setError(err instanceof Error ? err.message : "Failed to fetch job");
        timer = window.setTimeout(tick, POLL_MS);
      }
    };

    void tick();

    return () => {
      cancelled.current = true;
      if (timer !== undefined) window.clearTimeout(timer);
    };
  }, [jobId]);

  return {
    status,
    step,
    progress,
    error,
    videoUrl,
    heraCompletedClips,
    heraTotalClips,
    heraAttempt,
    heraMaxAttempts,
  };
}

import { Link, useParams } from "react-router-dom";
import Nav from "@/components/Nav";
import Footer from "@/components/Footer";
import JobProgress from "@/components/JobProgress";
import JobResult from "@/components/JobResult";
import ErrorBanner from "@/components/ErrorBanner";
import { useJobStatus } from "@/hooks/useJobStatus";
import { getVideoUrl } from "@/lib/api";

const JobPage = () => {
  const { jobId } = useParams<{ jobId: string }>();
  const {
    status,
    step,
    progress,
    error,
    videoUrl,
    heraCompletedClips,
    heraTotalClips,
    heraAttempt,
    heraMaxAttempts,
  } = useJobStatus(jobId);

  const isWorking = status === null || status === "pending" || status === "running";
  const isDone = status === "done";
  const isError = status === "error";

  return (
    <div className="min-h-screen bg-background flex flex-col">
      <Nav />
      <main className="flex-1 px-6 pb-16">
        <div className="max-w-2xl mx-auto bg-surface rounded-2xl shadow-sm p-8 mt-12 border border-border">
          {isWorking && (
            <>
              <h1 className="text-2xl font-semibold text-primary">Generating your briefing</h1>
              <p className="text-secondary mt-1">This usually takes 1 to 3 minutes.</p>
              <div className="mt-8">
                <JobProgress
                  step={step}
                  progress={progress}
                  heraCompletedClips={heraCompletedClips}
                  heraTotalClips={heraTotalClips}
                  heraAttempt={heraAttempt}
                  heraMaxAttempts={heraMaxAttempts}
                />
              </div>
              <div className="mt-8 text-center">
                <Link
                  to="/dashboard"
                  className="text-sm text-secondary hover:text-primary underline-offset-4 hover:underline"
                >
                  Cancel
                </Link>
              </div>
            </>
          )}

          {isDone && jobId && (
            <>
              <h1 className="text-2xl font-semibold text-primary">Your briefing is ready</h1>
              <p className="text-secondary mt-1">Review, share, or download.</p>
              <div className="mt-6">
                <JobResult videoUrl={videoUrl ?? getVideoUrl(jobId)} />
              </div>
            </>
          )}

          {isError && (
            <>
              <h1 className="text-2xl font-semibold text-primary">Generation failed</h1>
              <p className="text-secondary mt-1">We couldn&apos;t complete this briefing.</p>
              <div className="mt-6">
                <ErrorBanner message={error ?? "An unknown error occurred."} />
              </div>
              <div className="mt-6">
                <Link
                  to="/dashboard"
                  className="inline-flex items-center bg-accent text-accent-foreground rounded-lg px-5 py-3 font-medium hover:bg-accent/90 transition-colors"
                >
                  Try again
                </Link>
              </div>
            </>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
};

